{
  "id": "rainy_town_mod_001",
  "version": "1.0",
  "world_id": "rainy_town_world",
  "name": "雨镇异闻录：鬼伞之谜",
  "player_count_min": 2,
  "player_count_max": 4,
  "duration_minutes": 90,
  "opening_hook": "你们作为外来调查者，在一个暴雨倾盆的午后抵达雨镇。镇口茶楼的老板悄悄拉住你们，递上一把黑色油纸伞，低声说：‘这是我孙子阿水的伞，三天前他进柳家老宅找一只丢失的猫，再没出来。镇公所说他去了省城，但我知道他还在那宅子里。求你们带他回来，只有这把伞能开门。’",
  "core_secret": "老宅地下封印着一只‘雨魃’，它是因镇上先民屠杀水族而诞生的怨灵。暴雨是其愤怒的具现。失踪者并非走失，而是被雨魃拖入地窖，其灵魂被用于维持封印的脆弱平衡。",
  "major_conflict": "玩家在调查过程中受到两方势力拉扯：镇公所陈秘书试图掩盖老宅真相，阻挠深入调查；游方道人张先生则主张直接毁掉封印、彻底消灭雨魃，但这可能引发更大的灾难。玩家必须在镇公所的压制与道人的激进之间周旋，同时对抗不断累积的湿气值与灵异侵扰。",
  "required_npcs": [
    {
      "name": "陈秘书",
      "description": "镇公所文职人员，四十岁，戴圆框眼镜，说话滴水不漏。他坚持失踪者已自行离镇，并暗示外来者不要多管闲事。实际是水族后裔，暗中保护封印却怕真相暴露。",
      "role": "阻碍者/关键知情人"
    },
    {
      "name": "张先生",
      "description": "游方道人，五十岁，背一柄桃木剑，自称受委托来除妖。性格急躁，认为雨魃必须彻底消灭。他掌握部分古籍知识，但不知道超度之法。",
      "role": "激进协助者/潜在反派"
    },
    {
      "name": "阿水（柳明水）",
      "description": "茶楼老板的孙子，十五岁，被困于老宅地窖。他靠着黑伞里的符纸勉强存活，但已沾染湿气，精神恍惚。在玩家解救他时，他会提供关键线索：碑文的位置。",
      "role": "受害者/线索提供者"
    },
    {
      "name": "柳家老宅守门人-老柳",
      "description": "七十岁盲眼老人，住在老宅门房。他耳朵极灵，能通过雨声判断异变。他是水族后裔，知道封印真相但不愿多说。如果玩家给他喝热茶，他会暗示‘地窖入口在祠堂供桌下’。",
      "role": "隐晦指引者"
    }
  ],
  "key_locations": [
    {
      "name": "镇口茶楼",
      "description": "玩家初始地点，二楼窗户可见柳家老宅轮廓。茶楼老板提供黑伞与基础情报。后可作为安全休息点，消耗符纸降低湿气值。",
      "connections": ["柳家老宅", "雨神庙"]
    },
    {
      "name": "柳家老宅",
      "description": "三层木制大宅，年久失修，正堂挂满鱼纹饰物。一楼有厨房、客房，二楼是卧室，三楼是神龛。地窖入口藏在祠堂供桌下方。",
      "connections": ["镇口茶楼", "地窖"]
    },
    {
      "name": "雨神庙",
      "description": "镇外山上的小庙，庙内有一块石碑，碑文记载了四十九天暴雨与水族冤魂的事迹。庙中不可大声说话，否则引发雨魃注意。",
      "connections": ["镇口茶楼", "黄家祠堂"]
    },
    {
      "name": "黄家祠堂",
      "description": "供奉镇上历代先贤，但角落有一块被刻意铲去名字的牌位。牌位底部刻有‘乙亥年·柳公明’，暗示柳公明是当年屠杀水族的组织者。",
      "connections": ["雨神庙", "柳家老宅"]
    },
    {
      "name": "地窖（老宅地下）",
      "description": "狭小潮湿的石室，中央有一口井，井水呈现黑色。井壁上刻有雨魃真名（需通过三条线索拼合）。阿水被困在井旁。",
      "connections": ["柳家老宅"]
    }
  ],
  "key_clues": [
    {
      "description": "雨神庙石碑的残文：‘江城子·悼水族’中提到‘雨魃出，江水竭，四十九日，冤魂不散’。",
      "location": "雨神庙",
      "reveals": "确认雨魃的存在与暴雨的因果关系"
    },
    {
      "description": "黄家祠堂被铲去的牌位下，发现一封未寄出的信，署名柳公明，内容谴责自己‘当年为了田地屠杀水族，如今孽债自偿’。",
      "location": "黄家祠堂",
      "reveals": "指明雨魃的起源是柳公明组织的屠杀"
    },
    {
      "description": "地窖井壁上的碑文末尾刻着‘真名：沧溟’，但被风化了一半。若结合柳家老宅书房中一本水族族谱，可知‘沧溟’是水族祭祀的古语，意为‘深渊之怒’。",
      "location": "柳家老宅书房 + 地窖",
      "reveals": "雨魃真名‘沧溟’，念出即释放"
    }
  ],
  "threat_clock_id": "threat_rain_ba_clock",
  "endings": {
    "good": {
      "description": "玩家找到正确的超度仪轨：在雨神庙内用黑伞盛接无根水，滴入地窖井中，同时念出雨魃真名但附上水族安魂咒。雨魃怨气消散，暴雨渐停，阿水与之前失踪者灵魂归于安息。镇子恢复平静。",
      "trigger_condition": "收集全部三条关键线索，并在最终场景中使用正确咒语（需从游方道人处获得安魂咒残卷，或说服老柳念出水族祈祷词）"
    },
    "partial": {
      "description": "玩家选择帮助张道人强行破坏封印，雨魃被重创但未消失，暴雨减弱为绵绵细雨。然而封印彻底破损，雨魃分散为多个小水鬼，镇上开始频繁出现灵异事件。阿水获救但终身患有心病。",
      "trigger_condition": "玩家未集齐线索或选择直接武力破坏封印"
    },
    "bad": {
      "description": "玩家在地窖中好奇念出雨魃真名‘沧溟’，雨魃本体挣脱封印，引发巨大洪水淹没半个镇子。玩家被怨灵拖入井中，角色卡全部毁坏。镇子沦为鬼域。",
      "trigger_condition": "玩家在未完成超度准备的情况下直接念出真名，或触发黑伞禁忌（如用黑伞攻击怨灵）"
    }
  },
  "ai_do_not_change": "以下事实为模组核心设定，AI不得更改：1. 雨魃的真实身份是水族怨灵，由柳公明组织的屠杀造成；2. 黑色油纸伞是开启地窖门的钥匙，但其柄内藏有跟踪符咒（可被玩家发现）；3. 雨神庙内大声说话会触发雨魃幻象；4. 结局只有三种（good/partial/bad），且触发条件固定；5. 部分NPC（陈秘书、老柳）是水族后裔，拥有感知雨意的能力。",
  "ai_freedom_level": "AI可以在不改变上述核心事实的前提下自由调整：NPC对话细节、环境描写、次要线索的呈现方式、湿气值累计速率和灵异事件的具体描述。但不可增加新的结局种类，不可改变核心秘密（雨魃的成因与真名），不可让玩家获得直接战斗胜利的选项。"
}
